        let loadingtext = document.getElementById("loading-text");
        const changelater = "https://raw.githubusercontent.com/web-ports/milk-bag-games/refs/heads/main/inside/renpy.wasm";
        const originalFetch = window.fetch;
        window.fetch = async function(input, init) {
            let url = input;
            if (input instanceof Request) {
                url = input.url;
            }
            if (typeof url === "string" && url.endsWith("renpy.wasm")) {
                if (input instanceof Request) {
                    input = new Request(changelater, input);
                } else {
                    input = changelater;
                }
            }
            return originalFetch(input, init);
        };

        let doneparts = 0;

        function mergeFiles(fileParts) {
            return new Promise((resolve, reject) => {
                let buffers = [];

                function fetchPart(index) {
                    if (index >= fileParts.length) {
                        let mergedBlob = new Blob(buffers);
                        let mergedFileUrl = URL.createObjectURL(mergedBlob);
                        resolve(mergedFileUrl);
                        return;
                    }
                    fetch(fileParts[index]).then((response) => response.arrayBuffer()).then((data) => {
                        buffers.push(data);
                        doneparts = doneparts + 1;
                        loadingtext.textContent = "LOADING... (" + doneparts + "/" + maxparts + ")";
                        fetchPart(index + 1);
                    }).catch(reject);
                }
                fetchPart(0);
            });
        }

        let maxparts = 0;

        function getParts(file, start, end) {
            let parts = [];
            for (let i = start; i <= end; i++) {
                parts.push(file + ".part" + i);
            }
            maxparts = parts.length + maxparts;
            loadingtext.textContent = "LOADING... (" + doneparts + "/" + maxparts + ")";
            return parts;
        }
        mergeFiles(getParts("game.zip", 1, 7)).then(async url => {
            window.gameZipURL = url;
            let renpypre = document.createElement("script");
            renpypre.src = "renpy-pre.js"
            let renpy = document.createElement("script");
            renpy.src = "renpy.js"
            document.body.appendChild(renpypre);
            document.body.appendChild(renpy);
            loadingtext.remove();
        });
